import Overlay from './components/UI/Overlay/overlay';
import Home from './components/home/home';
import '../node_modules/bootstrap/dist/css/bootstrap.min.css';
function App() {
  return (
    <div className="App">
      <Header />
      <Hamburger />
      <SideDrawer >
        {/* there will be content here */}
      </SideDrawer>
      <Overlay /> 
      <Home />
    </div>
  );
}

export default App;
